import java.util.ArrayList;

class Student {
    private String name;
    private ArrayList<Integer> grades = new ArrayList<>();
    public Student(String n) { name = n; }
    public void addGrade(int g) { if (g>=0 && g<=100) grades.add(g); }
    public double getAverage() {
        if (grades.isEmpty()) return 0;
        int sum = 0; for (int g : grades) sum += g;
        return (double)sum / grades.size();
    }
    public int getHighest() {
        int max = 0; for (int g : grades) if (g > max) max = g; return max;
    }
    public String getLetterGrade() {
        double a = getAverage();
        if (a >= 90) return "A"; if (a >= 80) return "B";
        if (a >= 70) return "C"; if (a >= 60) return "D"; return "F";
    }
    public void display() {
        System.out.printf("%s | Grades: %s | Avg: %.1f | %s | %s%n",
            name, grades, getAverage(), getLetterGrade(), getAverage()>=50?"PASS":"FAIL");
    }
}
