    public static void main(String[] args) {
        Student s = new Student("Alice");
        s.addGrade(85); s.addGrade(92); s.addGrade(78);
        s.display();
    }
}

import java.util.ArrayList;

abstract class Shape {
    protected String name, colour;
    public Shape(String n, String c) { name=n; colour=c; }
    public abstract double getArea();
    public abstract double getPerimeter();
    public String toString() {
        return String.format("%s (%s) Area:%.2f Perim:%.2f", name, colour, getArea(), getPerimeter());
    }
}
class Circle extends Shape {
    double radius;
    Circle(double r, String c) { super("Circle",c); radius=r; }
    public double getArea() { return Math.PI*radius*radius; }
    public double getPerimeter() { return 2*Math.PI*radius; }
}
class Rect extends Shape {
    double w, h;
    Rect(double w, double h, String c) { super("Rectangle",c); this.w=w; this.h=h; }
    public double getArea() { return w*h; }
    public double getPerimeter() { return 2*(w+h); }
}
