        System.out.printf("Total area: %.2f%n", total);
    }
}

import java.util.ArrayList;

class BankAccount {
    protected String holder; protected double balance;
    public BankAccount(String h, double b) { holder=h; balance=Math.max(0,b); }
    public boolean deposit(double a) { if(a>0){balance+=a;return true;} return false; }
    public boolean withdraw(double a) { if(a>0&&a<=balance){balance-=a;return true;} return false; }
    public String toString() { return String.format("%s: $%.2f", holder, balance); }
}
class SavingsAccount extends BankAccount {
    double rate;
    SavingsAccount(String h, double b, double r) { super(h,b); rate=r; }
    void applyInterest() { double i=balance*rate; balance+=i; System.out.printf("Interest: $%.2f%n",i); }
}
class CurrentAccount extends BankAccount {
    double odLimit;
    CurrentAccount(String h, double b, double od) { super(h,b); odLimit=od; }
    public boolean withdraw(double a) {
        if(a>0 && a<=balance+odLimit) { balance-=a; return true; } return false;
    }
}
public class Banking {
    public static void main(String[] args) {
        SavingsAccount sa = new SavingsAccount("Alice",1000,0.05);
        CurrentAccount ca = new CurrentAccount("Bob",500,200);
        sa.deposit(500); sa.applyInterest();
        ca.withdraw(600); System.out.println("Bob overdraft: "+ca);
        System.out.println(sa); System.out.println(ca);
    }
}

