public class Quiz {
    public static void main(String[] args) {
        ArrayList<Question> qs = new ArrayList<>();
        qs.add(new Question("What does JVM stand for?", new String[]{"Java Virtual Machine","Java Visual Manager"},0));
        qs.add(new Question("Default int value?", new String[]{"null","0","1"},1));
        int score=0; int[] answers = {1,2};
        for(int i=0;i<qs.size();i++) {
            qs.get(i).display(i+1);
            System.out.println("Answer: "+answers[i]+(qs.get(i).check(answers[i])?" CORRECT!":" WRONG!"));
