public class PasswordCheck {
    static boolean hasUpper(String p) { for(char c:p.toCharArray()) if(Character.isUpperCase(c)) return true; return false; }
    static boolean hasLower(String p) { for(char c:p.toCharArray()) if(Character.isLowerCase(c)) return true; return false; }
    static boolean hasDigit(String p) { for(char c:p.toCharArray()) if(Character.isDigit(c)) return true; return false; }
    static boolean hasSpecial(String p) { for(char c:p.toCharArray()) if("!@#$%^&*".indexOf(c)>=0) return true; return false; }
    static int getScore(String p) {
        int s=0; if(p.length()>=8)s++; if(p.length()>=12)s++;
        if(hasUpper(p))s++; if(hasLower(p))s++; if(hasDigit(p))s++; if(hasSpecial(p))s++;
        return s;
    }
    static String getLabel(int s) { if(s<=2)return"WEAK"; if(s<=4)return"MODERATE"; return"STRONG"; }
    public static void main(String[] args) {
        String[] passwords = {"abc","Password1","S3cur3P@ss!"};
        for(String p:passwords) {
            int score = getScore(p);
            System.out.printf("%-15s Score:%d/6 %s%n", "*".repeat(p.length()), score, getLabel(score));
        }
    }
}

