public class TextAnalyser {
    static int countWords(String t) { return t.trim().isEmpty()?0:t.trim().split("\\s+").length; }
    static int countVowels(String t) {
        int c=0; for(char ch:t.toLowerCase().toCharArray()) if("aeiou".indexOf(ch)>=0) c++; return c;
    }
    static String findLongest(String t) {
        String longest=""; for(String w:t.split("\\s+"))
            if(w.replaceAll("[^a-zA-Z]","").length()>longest.length()) longest=w.replaceAll("[^a-zA-Z]","");
        return longest;
    }
    public static void main(String[] args) {
        String text = "Java is a powerful programming language used worldwide";
        System.out.println("Words: "+countWords(text));
        System.out.println("Vowels: "+countVowels(text));
        System.out.println("Longest: "+findLongest(text));
    }
}

