public class Calculator {
    static double add(double a, double b) { return a+b; }
    static double subtract(double a, double b) { return a-b; }
    static double multiply(double a, double b) { return a*b; }
    static double divide(double a, double b) {
        if(b==0) { System.out.println("ERROR: Divide by zero!"); return 0; }
        return a/b;
    }
    static long factorial(int n) {
        if(n<0) return -1; long r=1; for(int i=2;i<=n;i++) r*=i; return r;
    }
    public static void main(String[] args) {
        System.out.printf("10+3 = %.1f%n", add(10,3));
        System.out.printf("10/3 = %.2f%n", divide(10,3));
        System.out.printf("10/0 = "); divide(10,0);
        for(int i=1;i<=5;i++) System.out.printf("%d! = %d%n",i,factorial(i));
    }
}

import java.util.ArrayList;

class Candidate { String name; int votes; Candidate(String n){name=n;votes=0;} void addVote(){votes++;} }
public class Voting {
    static ArrayList<Candidate> candidates = new ArrayList<>();
    static ArrayList<String> voterIds = new ArrayList<>();
    static boolean vote(String vid, String cname) {
        if(voterIds.contains(vid)){System.out.println("REJECTED: "+vid+" already voted!");return false;}
        for(Candidate c:candidates) if(c.name.equalsIgnoreCase(cname)){c.addVote();voterIds.add(vid);return true;}
        return false;
    }
    public static void main(String[] args) {
        candidates.add(new Candidate("Alice")); candidates.add(new Candidate("Bob"));
        vote("V1","Alice"); vote("V2","Bob"); vote("V3","Alice"); vote("V1","Bob");
        int total=0; for(Candidate c:candidates) total+=c.votes;
        for(Candidate c:candidates)
            System.out.printf("%-10s %d votes (%4.1f%%) %s%n",c.name,c.votes,(double)c.votes/total*100,"#".repeat(c.votes*3));
    }
}

